import { Layer } from '@vis.gl/react-maplibre';

import type { BehaviorTrackingProps } from '@dynatrace/strato-components/core';

import { useSizeInterpolation } from './hooks/use-size-interpolation.js';
import { buildCircleStickToDistanceExpression } from './utils/build-stick-to-distance-expressions.js';
import {
  BUBBLE_DEFAULT_OPACITY,
  BUBBLE_STROKE,
  DEFAULT_RADIUS_EXPRESSION,
  SHAPE_OPACITY_DIMMED,
  SHAPE_OPACITY_DEFAULT,
} from '../../constants.js';

export const BubbleCircleLayer = ({
  id,
  source,
  ...behavioralTrackingProps
}: {
  id: string;
  source: string;
} & BehaviorTrackingProps) => {
  const sizeInterpolation = useSizeInterpolation();

  const radiusExpression =
    sizeInterpolation === 'fixed'
      ? DEFAULT_RADIUS_EXPRESSION
      : buildCircleStickToDistanceExpression();

  return (
    <Layer
      type="circle"
      id={id}
      source={source}
      paint={{
        'circle-color': [
          'case',
          ['boolean', ['feature-state', 'hover'], false],
          ['get', '__hoveredColor'],
          ['get', '__color'],
        ],
        'circle-radius': radiusExpression,
        'circle-opacity': [
          'case',
          ['boolean', ['feature-state', 'legendHover'], true],
          BUBBLE_DEFAULT_OPACITY,
          SHAPE_OPACITY_DIMMED,
        ],
        'circle-stroke-width': BUBBLE_STROKE,
        'circle-stroke-color': [
          'case',
          ['boolean', ['feature-state', 'hover'], false],
          ['get', '__hoveredColor'],
          ['get', '__color'],
        ],
        'circle-stroke-opacity': [
          'case',
          ['boolean', ['feature-state', 'legendHover'], true],
          SHAPE_OPACITY_DEFAULT,
          SHAPE_OPACITY_DIMMED,
        ],
      }}
      {...behavioralTrackingProps}
    />
  );
};
